module watchdog_timer (
  input clk,
  input reset,
  input [31:0] timer_duration,
  output reg timer_reset
);

reg [31:0] watchdog_counter;

always @(posedge clk or posedge reset) begin
  if (reset) begin
    watchdog_counter <= 0;
    timer_reset <= 0;
  end else begin
    watchdog_counter <= watchdog_counter + 1;
    if (watchdog_counter >= timer_duration) begin
      watchdog_counter <= 0;
      timer_reset <= 1;
    end else begin
      timer_reset <= 0;
    end
  end
end

endmodule
